package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.Instant;
import java.time.LocalDate;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that assigns elements to trading session windows based on market
 * session boundaries (e.g., NYSE 09:30-16:00 ET, LSE 08:00-16:30 GMT).
 *
 * <p>This assigner groups trading events by market session rather than fixed time intervals,
 * which is essential for capital markets streaming analytics where aggregations must align with
 * trading sessions.
 *
 * <p>The session window is determined by:
 * <ol>
 *   <li>The market ID (extracted from the element or provided at construction)
 *   <li>The element's timestamp
 *   <li>The market's session open/close times in its local timezone
 * </ol>
 *
 * @see PricingSessionTrigger
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    /**
     * Creates a new PricingSessionWindow assigner for a specific market.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone of the market (e.g., America/New_York for NYSE)
     * @param sessionOpen The market session opening time (e.g., LocalTime.of(9, 30))
     * @param sessionClose The market session closing time (e.g., LocalTime.of(16, 0))
     */
    public PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("marketId cannot be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("timezone cannot be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException("sessionOpen and sessionClose cannot be null");
        }
        if (!sessionOpen.isBefore(sessionClose)) {
            throw new IllegalArgumentException(
                    "sessionOpen must be before sessionClose for non-overnight sessions");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert the element timestamp to the market's local time to determine session
        Instant instant = Instant.ofEpochMilli(timestamp);
        ZonedDateTime zonedDateTime = instant.atZone(timezone);

        // Get the session window for this timestamp
        TimeWindow sessionWindow = getSessionWindowForTimestamp(zonedDateTime);

        return Collections.singletonList(sessionWindow);
    }

    /**
     * Determines the trading session window for the given timestamp in the market's timezone.
     *
     * <p>Logic:
     * <ul>
     *   <li>If the time is within sessionOpen to sessionClose on the same date, return that session
     *   <li>If the time is before sessionOpen, the session started yesterday
     *   <li>If the time is after sessionClose, the session starts today (elements arrive late)
     * </ul>
     *
     * @param zonedDateTime The timestamp in the market's timezone
     * @return A TimeWindow representing the trading session
     */
    private TimeWindow getSessionWindowForTimestamp(ZonedDateTime zonedDateTime) {
        LocalDate date = zonedDateTime.toLocalDate();
        LocalTime time = zonedDateTime.toLocalTime();

        LocalDate sessionDate;
        if (time.isBefore(sessionOpen)) {
            // Before market open - assign to yesterday's session
            sessionDate = date.minusDays(1);
        } else if (time.isAfter(sessionClose)) {
            // After market close - assign to today's session (or current session)
            sessionDate = date;
        } else {
            // Within session hours
            sessionDate = date;
        }

        // Convert session times back to epoch milliseconds
        ZonedDateTime sessionOpenZdt = sessionDate.atTime(sessionOpen).atZone(timezone);
        ZonedDateTime sessionCloseZdt = sessionDate.atTime(sessionClose).atZone(timezone);

        long sessionStartMs = sessionOpenZdt.toInstant().toEpochMilli();
        long sessionEndMs = sessionCloseZdt.toInstant().toEpochMilli();

        return new TimeWindow(sessionStartMs, sessionEndMs);
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public String toString() {
        return String.format(
                "PricingSessionWindow(market=%s, tz=%s, open=%s, close=%s)",
                marketId, timezone, sessionOpen, sessionClose);
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    /** Merge overlapping {@link TimeWindow}s. */
    @Override
    public void mergeWindows(Collection<TimeWindow> windows, MergeCallback<TimeWindow> c) {
        TimeWindow.mergeWindows(windows, c);
    }

    /**
     * Creates a new {@code PricingSessionWindow} {@link WindowAssigner} that assigns elements to
     * trading sessions based on market open/close times.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone of the market (e.g., America/New_York for NYSE)
     * @param sessionOpen The market session opening time (e.g., LocalTime.of(9, 30))
     * @param sessionClose The market session closing time (e.g., LocalTime.of(16, 0))
     * @return The pricing session window assigner
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
    }
}

