    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    /**
     * Creates a new PricingSessionWindow assigner for a specific market.
     *
     * @param marketId The market identifier (e.g., "NYSE", "LSE")
     * @param timezone The timezone of the market (e.g., America/New_York for NYSE)
     * @param sessionOpen The market session opening time (e.g., LocalTime.of(9, 30))
     * @param sessionClose The market session closing time (e.g., LocalTime.of(16, 0))
     */
    public PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("marketId cannot be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("timezone cannot be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException("sessionOpen and sessionClose cannot be null");
        }
        if (!sessionOpen.isBefore(sessionClose)) {
            throw new IllegalArgumentException(
                    "sessionOpen must be before sessionClose for non-overnight sessions");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert the element timestamp to the market's local time to determine session
        Instant instant = Instant.ofEpochMilli(timestamp);
        ZonedDateTime zonedDateTime = instant.atZone(timezone);

        // Get the session window for this timestamp
        TimeWindow sessionWindow = getSessionWindowForTimestamp(zonedDateTime);

        return Collections.singletonList(sessionWindow);
    }

    /**
     * Determines the trading session window for the given timestamp in the market's timezone.
     *
     * <p>Logic:
     * <ul>
     *   <li>If the time is within sessionOpen to sessionClose on the same date, return that session
     *   <li>If the time is before sessionOpen, the session started yesterday
     *   <li>If the time is after sessionClose, the session starts today (elements arrive late)
     * </ul>
     *
     * @param zonedDateTime The timestamp in the market's timezone
     * @return A TimeWindow representing the trading session
     */
    private TimeWindow getSessionWindowForTimestamp(ZonedDateTime zonedDateTime) {
        LocalDate date = zonedDateTime.toLocalDate();
        LocalTime time = zonedDateTime.toLocalTime();

        LocalDate sessionDate;
        if (time.isBefore(sessionOpen)) {
            // Before market open - assign to yesterday's session
            sessionDate = date.minusDays(1);
        } else if (time.isAfter(sessionClose)) {
            // After market close - assign to today's session (or current session)
            sessionDate = date;
        } else {
            // Within session hours
            sessionDate = date;
